from typing import List, Dict, Any, Optional
from leann.cli import LeannCLI
from leann.api import LeannBuilder, LeannSearcher
from pathlib import Path

def convert_cli_args_to_api_config(
    args_list: List[str],
    command_type: str = "build"
) -> Dict[str, Any]:
    """Convert CLI arguments to API configuration dictionary.

    Args:
        args_list: List of command line arguments
        command_type: Type of command ('build' or 'search')

    Returns:
        Dictionary containing API configuration extracted from CLI arguments
    """
    # Create LeannCLI instance to access argument parsing
    cli = LeannCLI()

    # Create parser and parse arguments
    parser = cli.create_parser()
    args = parser.parse_args(args_list)

    # Validate command type matches parsed command
    if args.command != command_type:
        raise ValueError(f"Command type mismatch: expected '{command_type}', got '{args.command}'")

    # Extract configuration based on command type
    if command_type == "build":
        return _extract_build_config(args)
    elif command_type == "search":
        return _extract_search_config(args)
    else:
        raise ValueError(f"Unsupported command type: {command_type}")

def _extract_build_config(args) -> Dict[str, Any]:
    """Extract configuration for build command from parsed arguments."""
    # Extract embedding options
    embedding_options = {}
    if args.embedding_mode == "ollama":
        embedding_options["host"] = resolve_ollama_host(args.embedding_host)
    elif args.embedding_mode == "openai":
        embedding_options["base_url"] = resolve_openai_base_url(args.embedding_api_base)
        resolved_embedding_key = resolve_openai_api_key(args.embedding_api_key)
        if resolved_embedding_key:
            embedding_options["api_key"] = resolved_embedding_key

    # Extract build configuration
    config = {
        "command": "build",
        "docs_paths": args.docs,
        "index_name": args.index_name,
        "force": args.force,
        "file_types": args.file_types,
        "include_hidden": args.include_hidden,
        "backend_name": args.backend_name,
        "embedding_model": args.embedding_model,
        "embedding_mode": args.embedding_mode,
        "embedding_options": embedding_options or None,
        "graph_degree": args.graph_degree,
        "complexity": args.complexity,
        "num_threads": args.num_threads,
        "compact": args.compact,
        "recompute": args.recompute,
        "use_ast_chunking": args.use_ast_chunking,
        "ast_chunk_size": args.ast_chunk_size,
        "ast_chunk_overlap": args.ast_chunk_overlap,
        "ast_fallback_traditional": args.ast_fallback_traditional
    }

    # Add prompt templates if provided
    if args.query_prompt_template:
        if "prompt_templates" not in config:
            config["prompt_templates"] = {}
        config["prompt_templates"]["query"] = args.query_prompt_template

    if args.embedding_prompt_template:
        if "prompt_templates" not in config:
            config["prompt_templates"] = {}
        config["prompt_templates"]["embedding"] = args.embedding_prompt_template

    return config

def _extract_search_config(args) -> Dict[str, Any]:
    """Extract configuration for search command from parsed arguments."""
    # Extract search configuration
    config = {
        "command": "search",
        "index_name": args.index_name,
        "query": args.query,
        "top_k": args.top_k,
        "complexity": args.complexity,
        "beam_width": args.beam_width,
        "prune_ratio": args.prune_ratio,
        "recompute_embeddings": args.recompute_embeddings,
        "pruning_strategy": args.pruning_strategy,
        "non_interactive": args.non_interactive,
        "show_metadata": args.show_metadata,
        "detail": args.detail,
        "num_threads": args.num_threads,
        "enable_warmup": getattr(args, 'warmup', False)  # Handle both old and new format
    }

    # Add prompt template if provided
    if args.embedding_prompt_template:
        config["embedding_prompt_template"] = args.embedding_prompt_template

    return config

# Helper functions from LeannCLI class (must be maintained for compatibility)
def resolve_ollama_host(explicit: str | None = None) -> str:
    """Resolve Ollama-compatible host with proper schema."""
    candidates = (
        explicit,
        os.getenv("LEANN_EMBEDDING_HOST"),
        os.getenv("LEANN_OLLAMA_HOST"),
        os.getenv("OLLAMA_HOST"),
        os.getenv("LOCAL_LLM_ENDPOINT"),
    )

    for candidate in candidates:
        if candidate:
            return _clean_url(candidate)

    return _clean_url(_DEFAULT_OLLAMA_HOST)

def resolve_openai_base_url(explicit: str | None = None) -> str:
    """Resolve base URL for OpenAI-compatible services."""
    candidates = (
        explicit,
        os.getenv("LEANN_OPENAI_BASE_URL"),
        os.getenv("OPENAI_BASE_URL"),
        os.getenv("LOCAL_OPENAI_BASE_URL"),
    )

    for candidate in candidates:
        if candidate:
            return _clean_url(candidate)

    return _clean_url(_DEFAULT_OPENAI_BASE_URL)

def resolve_openai_api_key(explicit: str | None = None) -> str | None:
    """Resolve API key for OpenAI-compatible services."""
    if explicit:
        return explicit
    return os.getenv("OPENAI_API_KEY")

def _clean_url(url: str) -> str:
    """Clean URL by ensuring proper formatting."""
    return url.rstrip('/')

